import { cn } from '@/utils/cn';
import {
  Component,
  createMemo,
  createSignal,
  For,
  mergeProps,
  on,
  createEffect,
  splitProps,
} from 'solid-js';
import type { RatingProps } from './rating.types';

const sizeClass: Record<string, string> = {
  xs: 'rating-xs',
  sm: 'rating-sm',
  md: 'rating-md',
  lg: 'rating-lg',
  xl: 'rating-xl',
};

/** Map BaseColorProps → Tailwind bg class; trả về nguyên string nếu không khớp */
function resolveColor(color?: string): string {
  const map: Record<string, string> = {
    primary: 'bg-primary',
    secondary: 'bg-secondary',
    accent: 'bg-accent',
    neutral: 'bg-neutral',
    info: 'bg-info',
    success: 'bg-success',
    warning: 'bg-warning',
    error: 'bg-error',
  };
  if (!color) return '';
  return map[color] ?? color;
}

/** Màu mặc định theo mask khi user không truyền color */
const DEFAULT_COLOR: Record<string, string> = {
  star: 'bg-yellow-400',
  'star-2': 'bg-orange-400',
  heart: 'bg-red-400',
};

/** Lookup đầy đủ để Tailwind CSS 4 scan được class strings */
const MASK_CLASS: Record<string, string> = {
  star: 'mask-star',
  'star-2': 'mask-star-2',
  heart: 'mask-heart',
};

const DEFAULT_PROPS: Partial<RatingProps> = {
  count: 5,
  mask: 'star-2',
  size: 'md',
  allowClear: true,
  half: false,
  readOnly: false,
};

let _uid = 0;

export const Rating: Component<RatingProps> = rawProps => {
  const [local, rest] = splitProps(mergeProps(DEFAULT_PROPS, rawProps), [
    'value',
    'defaultValue',
    'count',
    'color',
    'size',
    'mask',
    'readOnly',
    'half',
    'allowClear',
    'gap',
    'onChange',
    'class',
    'ariaLabel',
  ]);

  // unique name cho radio group
  const groupName = `rating-${++_uid}`;

  // Internal signal cho uncontrolled mode
  const [internal, setInternal] = createSignal<number>(local.defaultValue ?? 0);

  // Sync controlled value → internal
  createEffect(
    on(
      () => local.value,
      v => {
        if (v !== undefined) setInternal(v);
      },
    ),
  );

  const current = createMemo(() => (local.value !== undefined ? local.value : internal()));

  const handleChange = (val: number) => {
    if (local.readOnly) return;
    if (local.value === undefined) setInternal(val);
    local.onChange?.(val);
  };

  // Nếu user không truyền color, dùng màu mặc định theo mask
  const colorCls = createMemo(
    () => resolveColor(local.color) || DEFAULT_COLOR[local.mask ?? 'star-2'] || 'bg-orange-400',
  );
  const maskCls = createMemo(() => MASK_CLASS[local.mask ?? 'star-2'] ?? 'mask-star-2');

  // gap-1 mặc định bật cho heart, tắt cho star/star-2 (theo DaisyUI docs)
  const gapCls = createMemo(() => {
    const explicit = local.gap;
    if (explicit !== undefined) return explicit ? 'gap-1' : undefined;
    return local.mask === 'heart' ? 'gap-1' : undefined;
  });

  /** Danh sách các "step" value: nếu half thì 0.5, 1, 1.5 … sinon 1, 2, 3 … */
  const steps = createMemo<number[]>(() => {
    const total = local.count ?? 5;
    const list: number[] = [];
    if (local.half) {
      for (let i = 0.5; i <= total; i += 0.5) list.push(i);
    } else {
      for (let i = 1; i <= total; i++) list.push(i);
    }
    return list;
  });

  // ── READ-ONLY render ──────────────────────────────────────────────────────
  if (local.readOnly) {
    return (
      <div
        class={cn(
          'rating',
          sizeClass[local.size!],
          local.half && 'rating-half',
          gapCls(),
          local.class,
        )}
        {...rest}
      >
        <For each={steps()}>
          {step => {
            const isHalfFirst = local.half && step % 1 !== 0;
            const halfCls = isHalfFirst ? 'mask-half-1' : local.half ? 'mask-half-2' : undefined;
            // Với half mode: ẩn nửa phải (mask-half-2) của sao tại vị trí current
            // vì DaisyUI render nó mờ 20% tạo ảo giác sao thừa
            if (local.half && !isHalfFirst && step - 0.5 === current()) return null;
            return (
              <div
                class={cn('mask', maskCls(), halfCls, colorCls())}
                aria-current={step === current() ? 'true' : undefined}
              />
            );
          }}
        </For>
      </div>
    );
  }

  // ── INTERACTIVE render ────────────────────────────────────────────────────
  return (
    <div
      class={cn(
        'rating',
        sizeClass[local.size!],
        local.half && 'rating-half',
        gapCls(),
        local.class,
      )}
      {...rest}
    >
      {/* Input ẩn để reset */}
      {local.allowClear && (
        <input
          type="radio"
          name={groupName}
          class="rating-hidden"
          checked={current() === 0}
          aria-label="Reset rating"
          onChange={() => handleChange(0)}
        />
      )}

      <For each={steps()}>
        {step => {
          const isHalfFirst = local.half && step % 1 !== 0;
          const halfCls = isHalfFirst ? 'mask-half-1' : local.half ? 'mask-half-2' : undefined;
          const label = local.ariaLabel
            ? `${local.ariaLabel} ${step}`
            : `${step} ${local.half ? 'stars' : 'star'}`;

          return (
            <input
              type="radio"
              name={groupName}
              class={cn('mask', maskCls(), halfCls, colorCls())}
              checked={current() === step}
              aria-label={label}
              onChange={() => handleChange(step)}
            />
          );
        }}
      </For>
    </div>
  );
};
